using namespace std;
int main(){
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n, m; cin >> n >> m;
    vector<int> deg(n + 1, 0);
    for (int i = 0; i < m; i++) { int u, v; cin >> u >> v; deg[u]++; deg[v]++; }
    for (int i = 1; i <= n; i++) cout << deg[i] << (i == n ? '\n' : ' ');
